using namespace std;


pair < int, int > bfs(int start, vector < vector < int >> & adj) {

    queue < int > q;
    vector < int > dist(adj.size(), -1);
    int farthest = start;
    int max_dist = 0;


    q.push(start);
    dist[start] = 0;

    while (!q.empty()) {
        int node = q.front();
        q.pop();

        for (int neigh: adj[node]) {
            // cout<<"Visiting "<<neigh<<" - "<<dist[neigh].second<<endl;
            if (dist[neigh] == -1) {
                //cout<<"unvisite "<<neigh<<endl;
                dist[neigh] = dist[node] + 1;
                q.push(neigh);

                if (dist[neigh] > max_dist) {
                    max_dist = dist[neigh];
                    farthest = neigh;
                }
            }
        }
    }


    // vector of distances for each node
    return make_pair(farthest, max_dist);
}

