import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{

    static class Pair {
        int first, second;

        Pair(int first, int second) {
            this.first = first;
            this.second = second;
        }
    }

    public static Pair bfs(int start, List < List < Integer >> adj) {
        Queue < Integer > queue = new LinkedList < > ();
        int[] dist = new int[adj.size()];
        Arrays.fill(dist, -1);
        int farthest = start;
        int maxDist = 0;

        queue.add(start);
        dist[start] = 0;

        while (!queue.isEmpty()) {
            int node = queue.poll();

            for (int neigh: adj.get(node)) {
                if (dist[neigh] == -1) {
                    dist[neigh] = dist[node] + 1;
                    queue.add(neigh);

                    if (dist[neigh] > maxDist) {
                        maxDist = dist[neigh];
                        farthest = neigh;
                    }
                }
            }
        }
        return new Pair(farthest, maxDist);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();

        while (t--> 0) {
            int n = scanner.nextInt();
            List < List < Integer >> adjList = new ArrayList < > (n + 1);
            for (int i = 0; i <= n; i++) {
                adjList.add(new ArrayList < > ());
            }

            for (int i = 0; i < n - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                adjList.get(u).add(v);
                adjList.get(v).add(u);
            }

            Pair leaf = bfs(1, adjList);
            Pair diameter = bfs(leaf.first, adjList);
            System.out.println(diameter.second);
        }
        scanner.close();
    }
}
